from shapes import Shape, Circle, Rectangle, Square

def total_area(shapes: list[Shape]) -> float:
    total: float = 0.0
    for s in shapes:
        total = total + s.area()
    return total

def total_perimeter(shapes: list[Shape]) -> float:
    total: float = 0.0
    for s in shapes:
        total = total + s.perimeter()
    return total

def describe_shape(s: Shape) -> str:
    return f"{s} has area={s.area():.2f} and perimeter={s.perimeter():.2f}"

def create_sample_shapes() -> list[Shape]:
    result: list[Shape] = list()
    result.append(Circle(5.0))
    result.append(Rectangle(4.0, 6.0))
    result.append(Square(3.0))
    return result
